import{_ as l,C as s,o,c as n,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Cyprus Healthcare","description":"Healthcare and HRT access for transgender people in Cyprus","frontmatter":{"layout":"doc","title":"Cyprus Healthcare","description":"Healthcare and HRT access for transgender people in Cyprus"},"headers":[],"relativePath":"europe/cyprus/healthcare.md","filePath":"europe/cyprus/healthcare.md","lastUpdated":null}'),c={name:"europe/cyprus/healthcare.md"};function h(p,e,u,g,y,m){const t=s("Badge");return o(),n("div",null,[r(t,{variant:"red"},{default:a(()=>[...e[0]||(e[0]=[i("Gatekeeping Model",-1)])]),_:1}),r(t,{variant:"red"},{default:a(()=>[...e[1]||(e[1]=[i("Very Limited Services",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-cyprus" tabindex="-1">Healthcare in Cyprus <a class="header-anchor" href="#healthcare-in-cyprus" aria-label="Permalink to &quot;Healthcare in Cyprus&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Cyprus has very limited trans-specific healthcare services. The healthcare system operates a <strong>gatekeeping model</strong> and there are no dedicated gender identity clinics on the island.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Psychiatric diagnosis of gender dysphoria</li><li>Referral to an endocrinologist</li><li>Limited specialists with trans healthcare experience</li><li>Most services are in Nicosia and Limassol</li></ul><h3 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li><strong>Psychiatric Assessment</strong> — Find a psychiatrist with trans experience (very few available)</li><li><strong>Diagnosis</strong> — Gender dysphoria diagnosis</li><li><strong>Referral</strong> — To an endocrinologist for HRT</li><li><strong>HRT Initiation</strong> — After medical evaluation and blood work</li><li><strong>Monitoring</strong> — Regular follow-up with endocrinologist</li></ol><h3 id="key-providers" tabindex="-1">Key Providers <a class="header-anchor" href="#key-providers" aria-label="Permalink to &quot;Key Providers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Location</th><th>Services</th><th>Notes</th></tr></thead><tbody><tr><td>General Hospital Nicosia</td><td>Nicosia</td><td>Limited trans services</td><td>Psychiatry, endocrinology</td></tr><tr><td>General Hospital Limassol</td><td>Limassol</td><td>Limited trans services</td><td>Psychiatry, endocrinology</td></tr><tr><td>Private psychiatrists</td><td>Nicosia/Limassol</td><td>Assessment, diagnosis</td><td>Few with trans experience</td></tr><tr><td>Private endocrinologists</td><td>Nationwide</td><td>HRT prescription</td><td>Limited trans knowledge</td></tr><tr><td>Accept Cyprus referrals</td><td>Nationwide</td><td>LGBTQ+ referral network</td><td>Very helpful for finding providers</td></tr></tbody></table><h3 id="challenges" tabindex="-1">Challenges <a class="header-anchor" href="#challenges" aria-label="Permalink to &quot;Challenges&quot;">​</a></h3><ul><li><strong>No dedicated gender clinics</strong> on the island</li><li>Very few psychiatrists and endocrinologists with trans healthcare experience</li><li>Healthcare professionals often lack training in trans health</li><li>Many trans people travel abroad for healthcare (Greece, UK, Germany)</li><li>Stigma concerns in smaller communities</li><li>Appointment availability is limited</li></ul><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU member</strong> — EU prescription cross-border rules apply</li><li>EU/EEA prescriptions valid for up to 30 days</li><li>Cypriot prescriptions filled at local pharmacies</li><li>Non-EU prescriptions require doctor verification</li><li>HRT medications (oestradiol, testosterone) available at pharmacies</li></ul><h2 id="insurance-coverage" tabindex="-1">Insurance Coverage <a class="header-anchor" href="#insurance-coverage" aria-label="Permalink to &quot;Insurance Coverage&quot;">​</a></h2><p>Cyprus has the <strong>General Healthcare System (GESY)</strong> :</p><ul><li>Universal healthcare coverage for residents</li><li>Trans-related care included in principle</li><li>HRT medications partially covered</li><li>GP and specialist visits covered (small co-payment)</li><li>Surgery coverage requires approval</li><li>Private insurance available for supplemental coverage</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>Very limited surgical options</strong> in Cyprus</li><li>Most trans people travel abroad for surgery: <ul><li><strong>Greece</strong>: Common destination for surgeries</li><li><strong>Thailand</strong>: Popular for bottom surgery</li><li><strong>Spain/UK/Germany</strong>: For other procedures</li></ul></li><li>Insurance may contribute to overseas surgery costs with prior approval</li><li>Top surgery: limited availability, mostly private</li><li>Bottom surgery: not available locally</li></ul><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>Accept Cyprus</strong> — LGBTQ+ counselling and referral service</li><li><strong>Cyprus Family Planning Association</strong> — Counselling services</li><li>Private therapists: very few with trans experience</li><li>Online therapy options available</li><li>Peer support groups through Accept Cyprus</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Typical Cost</th><th>GESY Coverage</th></tr></thead><tbody><tr><td>GP visit</td><td>Covered</td><td>Yes (small co-pay)</td></tr><tr><td>Psychiatric assessment</td><td>€50-100 (private)</td><td>Partial</td></tr><tr><td>Endocrinology consult</td><td>Covered (public) / €60-120 (private)</td><td>Partial</td></tr><tr><td>HRT (monthly)</td><td>€15-40</td><td>Partial</td></tr><tr><td>Blood tests</td><td>Covered</td><td>Yes</td></tr><tr><td>Private therapy</td><td>€50-80</td><td>Not covered</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gesy.org.cy/" target="_blank" rel="noreferrer">GESY - General Healthcare System</a></li><li><a href="https://www.accept.cy/" target="_blank" rel="noreferrer">Accept Cyprus - Healthcare Guide</a></li><li><a href="https://www.cfpakp.org/" target="_blank" rel="noreferrer">Cyprus Family Planning Association</a></li><li><a href="https://www.moh.gov.cy/" target="_blank" rel="noreferrer">Ministry of Health Cyprus</a></li></ul>',25))])}const b=l(c,[["render",h]]);export{v as __pageData,b as default};
